const html = $json.data;
const urlOrigem = $node["Ler_Fontes_de_Busca"].json.url;
const nomeFonte = $node["Ler_Fontes_de_Busca"].json.nome_fonte;

if (!html) return [];

const match = html.match(/<script id="__NEXT_DATA__" type="application\/json">([\s\S]*?)<\/script>/);
if (!match) return [];

try {
  const data = JSON.parse(match[1]);
  const jobs = data.props.pageProps.jobs || [];
  const pattern = /aprendiz/i;
  const filteredJobs = jobs.filter(j => pattern.test(j.title));

  return filteredJobs.map(v => {
    const jobUrl = `${urlOrigem.replace(/\/$/, '')}/jobs/${v.id}`;
    const seed = jobUrl;
    let hash = 0;
    for (let i = 0; i < seed.length; i++) {
      const char = seed.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    const id = 'vaga_scr_' + Math.abs(hash).toString(36) + '_' + seed.length.toString(36);

    let localidade = 'Remoto';
    if (v.workplace && v.workplace.address) {
      const addr = v.workplace.address;
      localidade = `${addr.city || ''} - ${addr.stateShortName || ''}`.replace(/^ - | - $/g, '');
    }

    return {
      id,
      titulo: v.title,
      empresa: nomeFonte,
      localidade: localidade || 'Não especificado',
      descricao: `Vaga de Jovem Aprendiz no departamento ${v.department || 'Geral'}. Tipo: ${v.type || 'Aprendizado'}. Candidate-se no link original.`,
      url: jobUrl,
      origem: nomeFonte,
      data_publicacao: new Date().toISOString().split('T')[0],
      status: "PENDENTE",
      data_descoberta: new Date().toISOString()
    };
  });
} catch (e) {
  return [];
}
